12	// TestEvaluateRateLimitWait_RetryAfterRespected covers AC #3 of ddx-c6e3db02:
13	// when the response carries a Retry-After value, the policy honours it
14	// (subject to the per-wait cap and remaining budget).
15	func TestEvaluateRateLimitWait_RetryAfterRespected(t *testing.T) {
16		d := EvaluateRateLimitWait(20*time.Second, 1, 0, 5*time.Minute, 60*time.Second)
17		if !d.ShouldRetry {
18			t.Fatalf("ShouldRetry: got false; want true")
19		}
20		if d.Wait != 20*time.Second {
21			t.Fatalf("Wait: got %v; want 20s", d.Wait)
22		}
23		if d.Source != "retry-after" {
24			t.Fatalf("Source: got %q; want retry-after", d.Source)
25		}
26	}
