28	// Per-wait cap clamps an over-large Retry-After value.
29	func TestEvaluateRateLimitWait_RetryAfterClampedByPerWaitCap(t *testing.T) {
30		d := EvaluateRateLimitWait(10*time.Minute, 1, 0, 5*time.Minute, 60*time.Second)
31		if !d.ShouldRetry {
32			t.Fatalf("ShouldRetry: got false; want true")
33		}
34		if d.Wait != 60*time.Second {
35			t.Fatalf("Wait: got %v; want clamped 60s", d.Wait)
36		}
37	}
