39	// TestEvaluateRateLimitWait_ExponentialBackoffFallback covers AC #3: when
40	// Retry-After is absent the policy falls back to the published schedule
41	// (1s, 5s, 15s, 30s, 60s).
42	func TestEvaluateRateLimitWait_ExponentialBackoffFallback(t *testing.T) {
43		want := []time.Duration{
44			1 * time.Second,
45			5 * time.Second,
46			15 * time.Second,
47			30 * time.Second,
48			60 * time.Second,
49			// Beyond the schedule, repeat the last entry.
50			60 * time.Second,
51		}
52		for i, expected := range want {
53			d := EvaluateRateLimitWait(0, i+1, 0, 0, 0)
54			if !d.ShouldRetry {
55				t.Fatalf("attempt %d: ShouldRetry false", i+1)
56			}
57			if d.Source != "exponential-backoff" {
58				t.Fatalf("attempt %d: Source = %q; want exponential-backoff", i+1, d.Source)
59			}
60			if d.Wait != expected {
61				t.Fatalf("attempt %d: Wait = %v; want %v", i+1, d.Wait, expected)
62			}
63		}
64	}
