66	// Budget exhaustion: when elapsed already meets/exceeds budget, no retry.
67	func TestEvaluateRateLimitWait_BudgetExhausted(t *testing.T) {
68		d := EvaluateRateLimitWait(5*time.Second, 3, 5*time.Minute, 5*time.Minute, 60*time.Second)
69		if d.ShouldRetry {
70			t.Fatalf("ShouldRetry: got true; want false (budget exhausted)")
71		}
72		if d.Reason != RateLimitBudgetExhaustedReason {
73			t.Fatalf("Reason: got %q; want %q", d.Reason, RateLimitBudgetExhaustedReason)
74		}
75	}
