88	func TestParseRetryAfter(t *testing.T) {
89		now := time.Date(2026, 5, 3, 12, 0, 0, 0, time.UTC)
90		cases := []struct {
91			in   string
92			want time.Duration
93		}{
94			{"30", 30 * time.Second},
95			{"  60 ", 60 * time.Second},
96			{"-5", 0}, // negative seconds → zero
97			{"", 0},
98			{"15s", 15 * time.Second},
99			{"2m", 2 * time.Minute},
100		}
101		for _, c := range cases {
102			got := ParseRetryAfter(c.in, now)
103			if got != c.want {
104				t.Errorf("ParseRetryAfter(%q): got %v; want %v", c.in, got, c.want)
105			}
106		}
107		// HTTP-date 90s in the future (RFC1123 with GMT, the canonical HTTP form)
108		httpDate := now.Add(90 * time.Second).UTC().Format(http.TimeFormat)
109		if got := ParseRetryAfter(httpDate, now); got != 90*time.Second {
110			t.Errorf("ParseRetryAfter(http-date %q): got %v; want 90s", httpDate, got)
111		}
112		// HTTP-date in the past → zero
113		pastDate := now.Add(-1 * time.Hour).UTC().Format(http.TimeFormat)
114		if got := ParseRetryAfter(pastDate, now); got != 0 {
115			t.Errorf("ParseRetryAfter(past http-date): got %v; want 0", got)
116		}
117	}
