119	func TestExtractRetryAfterFromStderr(t *testing.T) {
120		now := time.Date(2026, 5, 3, 12, 0, 0, 0, time.UTC)
121		stderr := "Error: 429 Too Many Requests\nRetry-After: 45\nplease retry\n"
122		if got := ExtractRetryAfterFromStderr(stderr, now); got != 45*time.Second {
123			t.Errorf("got %v; want 45s", got)
124		}
125		if got := ExtractRetryAfterFromStderr("retry_after=12\n", now); got != 12*time.Second {
126			t.Errorf("retry_after=12: got %v; want 12s", got)
127		}
128		if got := ExtractRetryAfterFromStderr("nothing here", now); got != 0 {
129			t.Errorf("missing marker: got %v; want 0", got)
130		}
131	}
