134		cases := []struct {
135			name string
136			res  *Result
137			want bool
138		}{
139			{"nil", nil, false},
140			{"empty", &Result{}, false},
141			{
142				name: "early-cancel 429 in stderr",
143				res:  &Result{Error: "cancelled: auth/rate-limit detected (\\b429\\b)", Stderr: "HTTP/1.1 429 Too Many Requests"},
144				want: true,
145			},
146			{
147				name: "rate limit phrase in stderr",
148				res:  &Result{Stderr: "Rate limit exceeded; back off"},
149				want: true,
150			},
151			{
152				name: "ratelimit phrase in error",
153				res:  &Result{Error: "ratelimit hit"},
154				want: true,
155			},
156			{
157				name: "quota wording must NOT match (QuotaPauseContract owns it)",
158				res:  &Result{Error: "quota exceeded"},
159				want: false,
160			},
161			{
